"use client";

import React, {
  useRef,
  useState,
  useEffect,
  MouseEvent,
  ReactNode,
} from "react";

interface Clip {
  id: string;
  src: string;
  start: number;   // seconds
  duration: number; // seconds
  color: string;
}

export function UltraQualityVideoTimelineEditor() {
  const videoRef = useRef<HTMLVideoElement>(null);
  const timelineRef = useRef<HTMLDivElement>(null);

  const [duration, setDuration] = useState(0);
  const [currentTime, setCurrentTime] = useState(0);
  const [scale, setScale] = useState(100); // px per second
  const [clips, setClips] = useState<Clip[]>([
    {
      id: "c1",
      src: "https://www.w3schools.com/html/mov_bbb.mp4",
      start: 1,
      duration: 3,
      color: "bg-indigo-500",
    },
    {
      id: "c2",
      src: "https://www.w3schools.com/html/mov_bbb.mp4",
      start: 5,
      duration: 2,
      color: "bg-emerald-500",
    },
  ]);

  // Resize & drag state
  const [dragging, setDragging] = useState<{
    clipId: string;
    type: "move" | "resize-left" | "resize-right";
    originX: number;
    originVal: number;
  } | null>(null);

  // on video metadata load
  useEffect(() => {
    const v = videoRef.current;
    if (!v) return;
    const onLoaded = () => {
      setDuration(v.duration);
      // optionally adjust scale: fit  timeline width
      const width = timelineRef.current?.clientWidth || 600;
      setScale(width / Math.max(10, v.duration)); 
    };
    v.addEventListener("loadedmetadata", onLoaded);
    v.addEventListener("timeupdate", () => setCurrentTime(v.currentTime));
    return () => {
      v.removeEventListener("loadedmetadata", onLoaded);
    };
  }, []);

  // Playhead click or drag to seek
  const onTimelineClick = (e: MouseEvent) => {
    const rect = timelineRef.current!.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const t = x / scale;
    videoRef.current!.currentTime = Math.min(t, duration);
  };

  // Begin dragging or resizing a clip
  const onClipMouseDown = (
    e: MouseEvent,
    clip: Clip,
    type: "move" | "resize-left" | "resize-right"
  ) => {
    e.stopPropagation();
    setDragging({
      clipId: clip.id,
      type,
      originX: e.clientX,
      originVal:
        type === "move"
          ? clip.start
          : type === "resize-left"
          ? clip.start
          : clip.duration,
    });
  };

  // Mouse move updates move/resize
  const onMouseMove = (e: MouseEvent<HTMLDivElement>) => {
    if (!dragging) return;
    const deltaSec = (e.clientX - dragging.originX) / scale;
    setClips((list) =>
      list.map((c) => {
        if (c.id !== dragging.clipId) return c;
        if (dragging.type === "move") {
          return {
            ...c,
            start: Math.max(0, Math.min(duration - c.duration, dragging.originVal + deltaSec)),
          };
        }
        if (dragging.type === "resize-left") {
          const newStart = Math.min(
            dragging.originVal + deltaSec,
            c.start + c.duration - 0.5
          );
          const newDur = c.duration + (c.start - newStart);
          return { ...c, start: Math.max(0, newStart), duration: Math.max(0.5, newDur) };
        }
        // resize-right
        const newDur = Math.max(0.5, dragging.originVal + deltaSec);
        return { ...c, duration: Math.min(duration - c.start, newDur) };
      })
    );
  };

  const onMouseUp = () => setDragging(null);

  return (
    <div
      className="flex flex-col space-y-4 p-4 bg-gray-50 dark:bg-gray-900 h-full"
      onMouseMove={onMouseMove}
      onMouseUp={onMouseUp}
    >
      {/* Video Preview */}
      <div className="w-full bg-black rounded overflow-hidden shadow-lg">
        <video
          ref={videoRef}
          className="w-full"
          controls
          src={clips[0].src}
        />
      </div>

      {/* Timeline */}
      <div className="relative">
        {/* Time ruler */}
        <div className="flex select-none text-xs text-gray-600 dark:text-gray-400">
          {Array.from({ length: Math.ceil(duration) + 1 }, (_, i) => (
            <div
              key={i}
              className="flex-shrink-0 text-center border-r border-gray-300 dark:border-gray-700"
              style={{ width: `${scale}px` }}
            >
              {i}s
            </div>
          ))}
        </div>

        {/* Clips area */}
        <div
          ref={timelineRef}
          className="relative h-16 bg-gray-100 dark:bg-gray-800 overflow-x-auto cursor-pointer"
          onMouseDown={onTimelineClick}
        >
          {/* Playhead */}
          <div
            className="absolute top-0 bottom-0 w-px bg-red-500 pointer-events-none"
            style={{ left: `${currentTime * scale}px` }}
          />

          {/* Clip items */}
          {clips.map((clip) => (
            <div
              key={clip.id}
              className={`absolute top-2 h-12 ${clip.color} rounded shadow flex items-center`}
              style={{
                left: `${clip.start * scale}px`,
                width: `${clip.duration * scale}px`,
              }}
              onMouseDown={(e) => onClipMouseDown(e, clip, "move")}
            >
              {/* Left resize handle */}
              <div
                className="w-2 h-full bg-black/50 cursor-ew-resize"
                onMouseDown={(e) => onClipMouseDown(e, clip, "resize-left")}
              />
              <span className="flex-1 text-center text-white text-sm select-none">
                {clip.id}
              </span>
              {/* Right resize handle */}
              <div
                className="w-2 h-full bg-black/50 cursor-ew-resize"
                onMouseDown={(e) => onClipMouseDown(e, clip, "resize-right")}
              />
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}
